SELECT FROM blog_article a LEFT JOIN blog_user u ON a.author_id = u.id WHERE a.author_id IN
#{authorId}
ORDER BY DESC, a.published_at DESC, a.id DESC
ORDER BY a.featured_at DESC, a.published_at DESC, a.id DESC
ORDER BY a.published_at DESC, a.id DESC
ORDER BY a.view_count DESC, a.published_at DESC, a.id DESC
LIMIT #{limit}
OFFSET #{offset}

SELECT author_id, COUNT(*) as article_count, SUM(view_count) as total_views, SUM(like_count) as total_likes FROM blog_article WHERE status = 'PUBLISHED' AND deleted_at IS NULL
AND category = #{category}
AND published_at >= #{publishedAfter}
GROUP BY author_id ORDER BY SUM(view_count * 1 + like_count * 3 + comment_count * 5) DESC, total_views DESC, total_likes DESC LIMIT #{limit}

