mapper.select:
SELECT FROM blog_article a WHERE a.status = 'PUBLISHED' AND a.deleted_at IS NULL AND a.published_at >= DATE_SUB(NOW(), INTERVAL 2 YEAR)
AND a.id NOT IN
#{excludeArticleId}
ORDER BY ( LOG10(COALESCE(a.view_count, 0) + 1) * 12 + SQRT(COALESCE(a.like_count, 0)) * 18 + SQRT(COALESCE(a.comment_count, 0)) * 14 + SQRT(COALESCE(a.favorite_count, 0)) * 22 + CASE WHEN a.cover_url IS NOT NULL AND a.cover_url != '' AND a.cover_url NOT LIKE '%/default/article-cover%' THEN 4 ELSE 0 END + CASE WHEN a.summary IS NOT NULL AND a.summary != '' THEN 4 ELSE 0 END + CASE WHEN a.content IS NOT NULL AND CHAR_LENGTH(a.content) >= 1200 THEN 6 WHEN a.content IS NOT NULL AND CHAR_LENGTH(a.content) >= 500 THEN 3 ELSE 0 END + CASE WHEN a.published_at >= DATE_SUB(NOW(), INTERVAL 7 DAY) THEN 90 WHEN a.published_at >= DATE_SUB(NOW(), INTERVAL 30 DAY) THEN 55 WHEN a.published_at >= DATE_SUB(NOW(), INTERVAL 90 DAY) THEN 30 WHEN a.published_at >= DATE_SUB(NOW(), INTERVAL 365 DAY) THEN 12 ELSE 4 END ) DESC, a.published_at DESC, a.id DESC LIMIT #{limit}

SELECT 
FROM blog_article
WHERE status = 'PUBLISHED'
AND deleted_at IS NULL
AND id != #{excludeId}

    AND category = #{category}

ORDER BY (view_count * 1 + like_count * 3 + comment_count * 5) DESC, published_at DESC
LIMIT #{limit}

SELECT 
FROM blog_article
WHERE author_id = #{authorId}
AND status = 'PUBLISHED'
AND deleted_at IS NULL
AND id != #{excludeId}
ORDER BY published_at DESC, id DESC
LIMIT #{limit}

SELECT FROM blog_article a WHERE a.status = 'PUBLISHED' AND a.deleted_at IS NULL AND a.id != #{excludeId}
OR a.category = #{category}
OR EXISTS ( SELECT 1 FROM blog_article_tag t WHERE t.article_id = a.id AND t.deleted_at IS NULL AND t.tag_name IN
#{tag}
)
ORDER BY ( CASE WHEN a.category = #{category} THEN 3 ELSE 0 END
+ ( SELECT COUNT(1) * 5 FROM blog_article_tag score_tag WHERE score_tag.article_id = a.id AND score_tag.deleted_at IS NULL AND score_tag.tag_name IN
#{tag}
)
) DESC, (a.view_count * 1 + a.like_count * 3 + a.comment_count * 5) DESC, a.published_at DESC, a.id DESC LIMIT #{limit}

